async function esquecerUsuario(usuarioId: string) {
  await prisma.usuario.update({
    where: { id: usuarioId },
    data: {
      nome: anonimizar(usuario.nome),
      email: anonimizar(usuario.email),
      deletedAt: new Date(),
    },
  });
  await prisma.consentimento.deleteMany({
    where: { usuarioId },
  });
}

